"""Activity: Type Inspector

Eight questions on Python's dynamic type system: what type() reports for literals and simple expressions (including the surprising type of ordinary division), isinstance() checked against a tuple of types, bool being a genuine subclass of int, the fact that type annotations are pure documentation Python itself never enforces at runtime (only external tools like ty or mypy check them, and only before the program ever runs), duck typing versus explicit isinstance checks, and the difference between type(x) is int and isinstance(x, int) once subclasses are involved. Every explanation defines annotation, runtime checking, and static checking from scratch.
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "89a7b63dac4dd5acd8ef75a4206946d8f475bb3262360a50a3bb852e00b97c21"
_KEY_B = "221386f35d25a853478c9ed97e3501fa8160d82aee4443a3294592e46145d1e1"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

